alter table  conversa add column if not exists ativo boolean not null default true; drop index if exists conversaleadidkey; create index if not exists conversa_corretorid_ativo_idx on conversa(corretorid, ativo); create index if not exists conversa_leadid_ativo_idx on conversa(leadid, ativo); create unique index if not exists usuario_cpf_key on usuario(cpf) where cpf is not null; create unique index if not exists usuario_creci_key on usuario(creci) where creci is not null;